#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <cuda_runtime.h>

__inline__ unsigned long long rdtsc() 
{
    unsigned long long cycles;
    asm volatile ("rdtsc" : "=A" (cycles));
    return cycles;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

void
init(int argc, char** argv)
{
	if(3 == argc){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
	}else{
                printf("Usage: pathfiner width num_of_steps\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; rows > n; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; rows > i; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; cols > j; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; rows > i; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);

}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

__global__ void pathfinder_kernel(int* src, int* dst, int* wall_row, int cols) {
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n >= cols) return;

    int min = src[n];
    if (0 < n)
        min = MIN(min, src[n-1]);
    if (cols-1 > n)
        min = MIN(min, src[n+1]);

    dst[n] = wall_row[n] + min;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src, *dst, *temp;
    int min;

    dst = result;
    src = new int[cols];

    // CUDA setup
    int *d_src, *d_dst, *d_wall_row;
    size_t cols_size = cols * sizeof(int);

    cudaMalloc(&d_src, cols_size);
    cudaMalloc(&d_dst, cols_size);
    cudaMalloc(&d_wall_row, cols_size);

    // Initial copy: src (host) is empty/unused initially, but dst (result) has data
    // The loop logic: temp = src; src = dst; dst = temp;
    // First iteration: src becomes result (initial row), dst becomes the buffer we allocated as src
    // So we need to copy result to d_src for the first iteration

    cudaMemcpy(d_src, result, cols_size, cudaMemcpyHostToDevice);

    int block_size = 256;
    int num_blocks = (cols + block_size - 1) / block_size;

    pin_stats_reset();
    for (int t = 0; rows-1 > t; t++) {
        // Logic swap: temp = src; src = dst; dst = temp;
        // In CUDA pointers:
        // t=0: src points to result (data), dst points to new buffer
        // We want to read from current src (which holds previous row results) and write to dst
        // Then swap so dst becomes src for next iteration

        // Copy wall[t+1] to device
        cudaMemcpy(d_wall_row, wall[t+1], cols_size, cudaMemcpyHostToDevice);

        pathfinder_kernel<<<num_blocks, block_size>>>(d_src, d_dst, d_wall_row, cols);

        // Swap pointers for next iteration
        int* temp_ptr = d_src;
        d_src = d_dst;
        d_dst = temp_ptr;
    }
    cudaDeviceSynchronize();

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

    // Copy final result back to host dst (which corresponds to the last written buffer)
    // After the loop, d_src holds the latest data because of the swap at the end of the last iteration
    // Wait, let's trace:
    // Iteration t: read d_src, write d_dst. Swap: d_src <- d_dst, d_dst <- old_d_src.
    // So after loop, d_src holds the result of the last computation.

    cudaMemcpy(dst, d_src, cols_size, cudaMemcpyDeviceToHost);

#ifdef BENCH_PRINT

    for (int i = 0; cols > i; i++)

            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; cols > i; i++)

            printf("%d ",dst[i]) ;

    printf("\n") ;

#endif

    delete [] data;
    delete [] wall;
    delete [] dst;
    delete [] src;

    cudaFree(d_src);
    cudaFree(d_dst);
    cudaFree(d_wall_row);
}

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}
